INSERT INTO `agent_events` (`id`, `agent_id`, `title`, `summary`, `source`, `source_url`, `event_date`, `impact_level`, `related_entities`, `project_id`, `created_at`) VALUES ('evt_4ab146d7', 'agent_995e16db', '中芯国际联合国内设备商，在28nm工艺关键设备上取得验证突破', '据产业链消息，中芯国际与一家国内头部半导体设备厂商合作，其某款用于28nm制程的刻蚀设备已通过中芯国际的生产线验证，并开始小批量导入。这是国产替代的重要一步。', '中国证券报', '', '2026-04-09', 'medium', '[]', 'project_public', '2026-04-11 10:43:19');
INSERT INTO `agent_events` (`id`, `agent_id`, `title`, `summary`, `source`, `source_url`, `event_date`, `impact_level`, `related_entities`, `project_id`, `created_at`) VALUES ('evt_4c7dd76b', 'agent_995e16db', '美国对华半导体设备出口管制出现新动向，中芯国际供应链国产化进程受关注', '近期有外媒报道，美国可能进一步收紧对华先进半导体制造设备的出口许可。此背景下，市场密切关注中芯国际在设备、材料等环节的国产替代进展及供应链安全。', '财联社', '', '2026-04-03', 'high', '[]', 'project_public', '2026-04-11 10:43:19');
