INSERT INTO `agent_events` (`id`, `agent_id`, `title`, `summary`, `source`, `source_url`, `event_date`, `impact_level`, `related_entities`, `project_id`, `created_at`) VALUES ('evt_c6dda372', 'agent_995e16db', '华为等国内设计公司加大中芯国际订单，成熟制程产能利用率维持高位', '行业调研显示，2026年第一季度，包括华为海思在内的多家国内芯片设计公司，增加了对中芯国际成熟制程（特别是55nm至28nm）的投片量，公司相关产线维持高负荷运转。', '21世纪经济报道', '', '2026-04-05', 'medium', '[]', 'project_public', '2026-04-11 10:43:19');
INSERT INTO `agent_events` (`id`, `agent_id`, `title`, `summary`, `source`, `source_url`, `event_date`, `impact_level`, `related_entities`, `project_id`, `created_at`) VALUES ('evt_c9bf1a37', 'agent_995e16db', '中芯国际宣布14纳米及以上工艺节点扩产计划，以应对国内需求增长', '中芯国际在近期投资者交流会上透露，为满足国内客户对成熟制程（14nm及以上）的强劲需求，公司已启动新一轮扩产计划，重点提升28nm及40nm等节点的产能。', '证券时报', '', '2026-04-07', 'high', '[]', 'project_public', '2026-04-11 10:43:19');
INSERT INTO `agent_events` (`id`, `agent_id`, `title`, `summary`, `source`, `source_url`, `event_date`, `impact_level`, `related_entities`, `project_id`, `created_at`) VALUES ('evt_e91c9eb8', 'demo_agent_lithium', '碳酸锂价格上涨 60.00%', '监测到碳酸锂最新价格由 12.50 变为 20.00，单次波动 +60.00%，已触发价格传导分析。', 'seed', '', '2026-04-15', 'high', '[\"碳酸锂\",\"电池电解液\",\"正极材料\",\"电芯\",\"电池\",\"新能源汽车\"]', 'project_public', '2026-04-16 14:14:57');
INSERT INTO `agent_events` (`id`, `agent_id`, `title`, `summary`, `source`, `source_url`, `event_date`, `impact_level`, `related_entities`, `project_id`, `created_at`) VALUES ('evt_f37d09ac', 'demo_agent_lithium', '碳酸锂价格上涨 60.00%', '监测到碳酸锂最新价格由 12.50 变为 20.00，单次波动 +60.00%，已触发价格传导分析。', 'seed', '', '2026-04-15', 'high', '[\"碳酸锂\",\"电池电解液\",\"正极材料\",\"电芯\",\"电池\",\"新能源汽车\"]', 'project_public', '2026-04-16 07:12:46');
