INSERT INTO `agents` (`id`, `name`, `description`, `target_company`, `target_industry`, `analysis_focus`, `schedule_minutes`, `is_active`, `project_id`, `last_run_at`, `created_at`, `updated_at`) VALUES ('demo_agent_lithium', '碳酸锂标的跟踪', '跟踪碳酸锂价格变化，并持续观察其向电解液、电芯和动力电池环节的成本传导。', '碳酸锂', '锂电材料', '价格波动、成本传导、电池链盈利压力', 120, 1, 'project_public', NULL, '2026-04-15 09:00:00', '2026-04-15 09:00:00');
INSERT INTO `ai_conversations` (`id`, `title`, `messages`, `preview_ontology`, `project_id`, `created_at`, `updated_at`) VALUES ('conv_11ee739e', '请帮我生成一个电商平台的本体，包括商品、订单、用户、店铺、评…', '[{role=system, text=欢迎使用 AI Studio！我是你的本体建模助手。\n\n你可以：\n• 描述你的业务领域，我来生成完整的数据本体\n• 要求我添加、修改或删除实体和关系\n• 让我为已有本体添加语义层信息\n• 提问关于本体设计的最佳实践\n\n每次对话我都会在已有本体基础上迭代改进。}, {role=user, text=请帮我生成一个电商平台的本体，包括商品、订单、用户、店铺、评价、物流等核心实体}, {role=assistant, text=好的，作为Palantir Foundry Ontology专家，我将为您设计一个电商平台的本体。您提供的当前本体是关于新能源电池供应链的，我们将在此基础上**新增**电商相关的核心对象类型、属性和关系，并保持原有结构不变。\n\n以下是针对您需求的电商平台本体设计方案，包含新增的6个核心对象类型和它们之间的关系。\n\n### 新增对象类型 (Object Types)\n\n```json\n[\n  {\n    \"id\": \"user\",\n    \"name\": \"用户\",\n    \"description\": \"电商平台的注册用户，可以是买家或卖家。\",\n    \"icon\": \"User\",\n    \"backingDataset\": \"user\",\n    \"dataSource\": \"mysql\",\n    \"database\": null,\n    \"industryId\": null,\n    \"createdAt\": \"2026-04-10T10:00:00\",\n    \"updatedAt\": \"2026-04-10T10:00:00\",\n    \"properties\": [\n      {\n        \"id\": \"p_user_id\",\n        \"objectTypeId\": \"user\",\n        \"name\": \"用户ID\",\n        \"type\": \"string\",\n        \"description\": \"用户的唯一标识符\",\n        \"isPrimaryKey\": 1,\n        \"baseColumn\": \"user_id\",\n        \"typeClasses\": null,\n        \"sortOrder\": 0\n      },\n      {\n        \"id\": \"p_username\",\n        \"objectTypeId\": \"user\",\n        \"name\": \"用户名\",\n        \"type\": \"string\",\n        \"description\": \"用户登录名或昵称\",\n        \"isPrimaryKey\": 0,\n        \"baseColumn\": \"username\",\n        \"typeClasses\": null,\n        \"sortOrder\": 1\n      },\n      {\n        \"id\": \"p_email\",\n        \"objectTypeId\": \"user\",\n        \"name\": \"邮箱\",\n        \"type\": \"string\",\n        \"description\": \"用户注册邮箱\",\n        \"isPrimaryKey\": 0,\n        \"baseColumn\": \"email\",\n        \"typeClasses\": null,\n        \"sortOrder\": 2\n      },\n      {\n        \"id\": \"p_phone\",\n        \"objectTypeId\": \"user\",\n        \"name\": \"手机号\",\n        \"type\": \"string\",\n        \"description\": \"用户绑定手机号\",\n        \"isPrimaryKey\": 0,\n        \"baseColumn\": \"phone\",\n        \"typeClasses\": null,\n        \"sortOrder\": 3\n      },\n      {\n        \"id\": \"p_registration_date\",\n        \"objectTypeId\": \"user\",\n        \"name\": \"注册日期\",\n        \"type\": \"date\",\n        \"description\": \"用户注册时间\",\n        \"isPrimaryKey\": 0,\n        \"baseColumn\": \"registration_date\",\n        \"typeClasses\": null,\n        \"sortOrder\": 4\n      },\n      {\n        \"id\": \"p_user_level\",\n        \"objectTypeId\": \"user\",\n        \"name\": \"用户等级\",\n        \"type\": \"string\",\n        \"description\": \"如：普通会员、VIP会员、钻石会员\",\n        \"isPrimaryKey\": 0,\n        \"baseColumn\": \"user_level\",\n        \"typeClasses\": null,\n        \"sortOrder\": 5\n      }\n    ]\n  },\n  {\n    \"id\": \"shop\",\n    \"name\": \"店铺\",\n    \"description\": \"商家在平台上开设的店铺，用于销售商品。\",\n    \"icon\": \"Store\",\n    \"backingDataset\": \"shop\",\n    \"dataSource\": \"mysql\",\n    \"database\": null,\n    \"industryId\": null,\n    \"createdAt\": \"2026-04-10T10:00:00\",\n    \"updatedAt\": \"2026-04-10T10:00:00\",\n    \"properties\": [\n      {\n        \"id\": \"p_shop_id\",\n        \"objectTypeId\": \"shop\",\n        \"name\": \"店铺ID\",\n        \"type\": \"string\",\n        \"description\": \"店铺的唯一标识符\",\n        \"isPrimaryKey\": 1,\n        \"baseColumn\": \"shop_id\",\n        \"typeClasses\": null,\n        \"sortOrder\": 0\n      },\n      {\n        \", ontology=null, streaming=false}]', NULL, 'project_public', '2026-04-10 23:11:21', '2026-04-10 23:11:42');
INSERT INTO `ai_conversations` (`id`, `title`, `messages`, `preview_ontology`, `project_id`, `created_at`, `updated_at`) VALUES ('conv_197f5e1d', '现在有多少个对象类型？', '[{role=system, text=欢迎使用 AI本体建模！我是你的本体建模助手。\n\n你可以：\n• 描述你的业务领域，我来生成完整的数据本体\n• 要求我添加、修改或删除实体和关系\n• 让我为已有本体添加语义层信息\n• 提问关于本体设计的最佳实践\n\n每次对话我都会在已有本体基础上迭代改进。}, {role=user, text=现在有多少个对象类型？}, {role=assistant, text=根据当前已有的本体信息，目前共有 **8 个对象类型（Object Type）**，具体如下：\n\n1. **事件**（`event_entity`）\n2. **公司**（`company_entity`）\n3. **新能源整车**（`new_energy_vehicle`）\n4. **正极材料**（`cathode_material`）\n5. **电池**（`power_battery`）\n6. **电池电解液**（`battery_electrolyte`）\n7. **电芯**（`battery_cell`）\n8. **碳酸锂**（`lithium_carbonate`）\n\n---\n\n### 当前本体概览\n\n| 对象类型 ID | 名称 | 主键 | 关键属性 |\n|---|---|---|---|\n| `event_entity` | 事件 | `id` | 标题、摘要、正文、分类、来源、日期、标签 |\n| `company_entity` | 公司 | `company_id` | 名称、股票代码、上市市场、所属行业 |\n| `new_energy_vehicle` | 新能源整车 | `vehicle_id` | 品牌、车型、指导价、续航、电池容量、是否在售等 |\n| `cathode_material` | 正极材料 | `material_id` | 名称、价格、价格日期 |\n| `power_battery` | 电池 | `unique_id` | 型号、容量、电压、化学类型、制造商、价格等 |\n| `battery_electrolyte` | 电池电解液 | `unique_id` | 名称、类型、价格、价格日期 |\n| `battery_cell` | 电芯 | `unique_id` | 型号、生产厂家、价格、价格日期 |\n| `lithium_carbonate` | 碳酸锂 | `unique_id` | 品级、生产厂家、价格、价格日期 |\n\n---\n\n### 关系链路（14 个 Link Type）\n\n当前本体已经构建了从 **原材料 → 电芯 → 电池 → 整车** 的完整产业链关系，同时支持事件影响分析：\n\n```\n事件 → 公司 / 整车 / 碳酸锂\n公司 → 供应商 / 战略合作 / 整车 / 电池 / 电芯 / 碳酸锂\n正极材料 → 碳酸锂\n电池 → 电芯\n电芯 → 正极材料 / 电解液\n电解液 → 碳酸锂\n电池 → 整车\n```\n\n---\n\n### 动作类型（Action Type）\n\n目前已定义 **40+ 个动作类型**，涵盖了：\n- **对象创建/更新/删除**：为每个 Object Type 都提供了 CRUD 操作\n- **链接创建/删除**：为每个 Link Type 提供了 Create/Delete 动作\n- **通知效果**：部分动作已配置了通知反馈\n\n---\n\n请问您希望对这个本体进行哪些具体的修改或扩展？例如：\n- 添加新的对象类型？\n- 修改现有对象类型的属性？\n- 添加或调整关系？\n- 优化动作类型？, ontology=null, streaming=false}]', NULL, 'project_public', '2026-04-24 12:00:10', '2026-04-24 12:00:21');
INSERT INTO `ai_conversations` (`id`, `title`, `messages`, `preview_ontology`, `project_id`, `created_at`, `updated_at`) VALUES ('conv_56e779b1', 'unique_id:LC-IN-001-2024，这款碳酸锂…', '[{role=system, text=欢迎使用 AI Studio！我是你的本体建模助手。\n\n你可以：\n• 描述你的业务领域，我来生成完整的数据本体\n• 要求我添加、修改或删除实体和关系\n• 让我为已有本体添加语义层信息\n• 提问关于本体设计的最佳实践\n\n每次对话我都会在已有本体基础上迭代改进。}, {role=user, text=unique_id:LC-IN-001-2024，这款碳酸锂的最新价格变成 20.6万元/吨，那么其关联的对象类型价格如何变化，这里请用 函数类型中定义的碳酸锂价格传导分析 的函数计算}, {role=assistant, text=根据您的需求，您希望当 `unique_id` 为 `LC-IN-001-2024` 的碳酸锂对象价格更新为 20.6 万元/吨时，触发一个预定义的“碳酸锂价格传导分析”函数，来计算并更新其关联对象（电解液、正极材料、电芯、电池、整车）的价格。\n\n分析当前本体，我发现以下问题需要解决：\n1.  **缺少关键对象类型**：当前本体中没有 `function_type`（函数类型）对象，无法定义和引用“碳酸锂价格传导分析”这个函数。\n2.  **缺少关联关系**：`lithium_carbonate` 对象类型与 `function_type` 对象类型之间没有建立关系，无法在动作中引用该函数。\n3.  **现有动作不匹配**：现有的 `act_vehicle_price` 动作是直接调整整车价格，其逻辑（通过参数手动输入变化比例）与您描述的“通过函数计算”的需求不符。\n4.  **缺少触发机制**：没有定义当碳酸锂价格属性更新时，如何自动触发计算。\n\n为了满足您的需求，我们需要对本体进行以下修改和补充：\n\n### 1. 新增 `function_type` 对象类型\n首先，需要创建一个新的对象类型来承载业务函数或计算模型。\n\n```json\n{\n  \"id\": \"function_type\",\n  \"name\": \"函数类型\",\n  \"description\": \"用于定义和存储业务计算函数或分析模型\",\n  \"icon\": \"Function\",\n  \"backingDataset\": \"function_type\",\n  \"industryId\": null,\n  \"createdAt\": \"2026-04-11T10:30:00\", // 请使用当前时间\n  \"updatedAt\": \"2026-04-11T10:30:00\",\n  \"status\": \"active\",\n  \"properties\": [\n    {\n      \"id\": \"p_function_id\",\n      \"objectTypeId\": \"function_type\",\n      \"name\": \"函数唯一标识符\",\n      \"type\": \"string\",\n      \"description\": null,\n      \"isPrimaryKey\": 1,\n      \"baseColumn\": \"function_id\",\n      \"typeClasses\": null,\n      \"sortOrder\": 0\n    },\n    {\n      \"id\": \"p_function_name\",\n      \"objectTypeId\": \"function_type\",\n      \"name\": \"函数名称\",\n      \"type\": \"string\",\n      \"description\": null,\n      \"isPrimaryKey\": 0,\n      \"baseColumn\": \"function_name\",\n      \"typeClasses\": null,\n      \"sortOrder\": 1\n    },\n    {\n      \"id\": \"p_description\",\n      \"objectTypeId\": \"function_type\",\n      \"name\": \"函数描述\",\n      \"type\": \"string\",\n      \"description\": \"描述函数的用途、输入、输出和计算逻辑\",\n      \"is, ontology=null, streaming=false}]', NULL, 'project_public', '2026-04-12 21:08:49', '2026-04-12 21:09:05');
INSERT INTO `ai_conversations` (`id`, `title`, `messages`, `preview_ontology`, `project_id`, `created_at`, `updated_at`) VALUES ('conv_58161fe8', '这个本体包括哪些object', '[{role=system, text=欢迎使用 AI Studio！我是你的本体建模助手。\n\n你可以：\n• 描述你的业务领域，我来生成完整的数据本体\n• 要求我添加、修改或删除实体和关系\n• 让我为已有本体添加语义层信息\n• 提问关于本体设计的最佳实践\n\n每次对话我都会在已有本体基础上迭代改进。}, {role=user, text=这个本体包括哪些object}, {role=assistant, text=根据您提供的本体 JSON 数据，当前系统中已定义了以下 **6个 Object Type（对象类型）**：\n\n1.  **`new_energy_vehicle`** - 新能源整车\n    *   **描述**: 新能源整车\n    *   **主键属性**: `vehicle_id` (车辆唯一标识符)\n    *   **关键属性**: 品牌、车型、价格、电池容量、续航里程等。\n\n2.  **`power_battery`** - 电池\n    *   **描述**: 电池\n    *   **主键属性**: `unique_id`\n    *   **关键属性**: 型号、制造商、容量、电压、化学类型、价格等。\n\n3.  **`battery_cell`** - 电芯\n    *   **描述**: 电芯\n    *   **主键属性**: `unique_id`\n    *   **关键属性**: 型号、生产厂家、价格等。\n\n4.  **`cathode_material`** - 正极材料\n    *   **描述**: 正极材料\n    *   **主键属性**: `material_id`\n    *   **关键属性**: 材料名称、价格等。\n\n5.  **`battery_electrolyte`** - 电池电解液\n    *   **描述**: 电池电解液\n    *   **主键属性**: `unique_id`\n    *   **关键属性**: 名称、类型、价格等。\n\n6.  **`lithium_carbonate`** - 碳酸锂\n    *   **描述**: 碳酸锂\n    *   **主键属性**: `unique_id`\n    *   **关键属性**: 品级、生产厂家、价格等。\n\n**关系总结**:\n从 `linkTypes` 部分可以看出，这些对象通过一个清晰的供应链关系连接起来：\n`碳酸锂` -> `正极材料` & `电解液` -> `电芯` -> `电池` -> `新能源整车`。\n\n这是一个非常典型的从原材料到最终产品的垂直行业本体模型。\n\n**接下来，您希望如何修改或完善这个本体呢？** 例如：\n*   是否需要为现有对象类型**添加新的属性**（如成本、供应商、技术参数）？\n*   是否需要**创建新的对象类型**来扩展模型（如`负极材料`、`隔膜`、`电池管理系统BMS`、`充电桩`、`车主`等）？\n*   是否需要**调整现有的关系**（`linkTypes`）的基数或描述？\n*   是否需要为业务流程**设计新的动作类型**（`Action Types`）？, ontology=null, streaming=false}]', NULL, 'project_public', '2026-04-10 23:01:31', '2026-04-10 23:01:48');
INSERT INTO `ai_conversations` (`id`, `title`, `messages`, `preview_ontology`, `project_id`, `created_at`, `updated_at`) VALUES ('conv_d961d618', '请帮我生成一个医院管理系统的完整本体，包括医生、患者、科室、…', '[{role=system, text=欢迎使用 AI Studio！我是你的本体建模助手。\n\n你可以：\n• 描述你的业务领域，我来生成完整的数据本体\n• 要求我添加、修改或删除实体和关系\n• 让我为已有本体添加语义层信息\n• 提问关于本体设计的最佳实践\n\n每次对话我都会在已有本体基础上迭代改进。}, {role=user, text=请帮我生成一个医院管理系统的完整本体，包括医生、患者、科室、病房、处方、检查报告等核心实体}, {role=assistant, text=我将为您设计一个完整的医院管理系统本体。基于您提到的核心实体（医生、患者、科室、病房、处方、检查报告），我将创建相应的对象类型、属性、关系类型和动作类型。\n\n以下是完整的医院管理系统本体设计：\n\n```json\n{\n  \"objectTypes\": [\n    {\n      \"id\": \"patient\",\n      \"name\": \"患者\",\n      \"description\": \"医院的患者信息\",\n      \"icon\": \"User\",\n      \"backingDataset\": \"patient_dataset\",\n      \"industryId\": null,\n      \"createdAt\": \"2026-04-11T10:30:00\",\n      \"updatedAt\": \"2026-04-11T10:30:00\",\n      \"status\": \"active\",\n      \"properties\": [\n        {\n          \"id\": \"p_patient_id\",\n          \"objectTypeId\": \"patient\",\n          \"name\": \"患者ID\",\n          \"type\": \"string\",\n          \"description\": \"患者的唯一标识符（病历号）\",\n          \"isPrimaryKey\": 1,\n          \"baseColumn\": \"patient_id\",\n          \"typeClasses\": null,\n          \"sortOrder\": 0\n        },\n        {\n          \"id\": \", ontology=null, streaming=false}]', NULL, 'project_public', '2026-04-12 14:18:22', '2026-04-12 14:18:31');
INSERT INTO `ai_conversations` (`id`, `title`, `messages`, `preview_ontology`, `project_id`, `created_at`, `updated_at`) VALUES ('conv_f41919be', '我想要新增一个 测试 本体类型', '[{role=system, text=欢迎使用 AI Studio！我是你的本体建模助手。\n\n你可以：\n• 描述你的业务领域，我来生成完整的数据本体\n• 要求我添加、修改或删除实体和关系\n• 让我为已有本体添加语义层信息\n• 提问关于本体设计的最佳实践\n\n每次对话我都会在已有本体基础上迭代改进。}, {role=user, text=我想要新增一个 测试 本体类型}, {role=assistant, text=好的，收到您的需求。您想要新增一个名为“测试”的本体类型。\n\n首先，我需要澄清一下，在 Foundry Ontology 的语境中，“测试”是一个比较宽泛的概念。为了确保我们创建的对象类型（Object Type）有意义、可维护，并且能真正融入您现有的业务图谱，我们需要明确几个关键点：\n\n1.  **业务含义**：这个“测试”具体指什么？例如：\n    *   **产品测试报告**：对电池、电芯等产品的性能、安全测试结果。\n    *   **原材料质检**：对碳酸锂、电解液等原材料的质量检验。\n    *   **生产流程测试**：电芯或电池组装过程中的某个环节测试。\n    *   **研发测试**：新型正极材料或电解液的研发阶段测试。\n\n2.  **数据来源**：这个对象类型将由哪个数据集支持？（`backing_dataset` 字段）。这是本体设计的核心，必须有一个真实的数据集作为基础。\n\n3.  **与现有图谱的关系**：这个“测试”对象应该与哪些现有对象关联？例如：\n    *   一份 `测试报告` 可能针对一个具体的 `电池` 或 `电芯`。\n    *   一次 `质检` 对应一批 `碳酸锂` 原材料。\n\n为了给您提供一个具体、可用的方案，我将基于最常见的假设为您设计：**这是一个针对“电池”或“电芯”的“性能与安全测试报告”**。\n\n如果您有更具体的业务场景，请随时告诉我，我们可以基于此进行调整。\n\n---\n\n### **方案设计：新增 `test_report` (测试报告) 对象类型**\n\n**设计思路**：\n*   **ID**: `test_report` (遵循现有命名风格，使用英文小写和下划线)\n*   **名称**: `测试报告`\n*   **描述**: 记录对电池、电芯等产品的性能与安全测试结果。\n*   **关联**: 主要与 `power_battery` (电池) 和 `battery_cell` (电芯) 关联，一份报告测试一个具体对象。\n*   **属性**: 包含测试标准、结果、日期、状态等关键信息。\n\n#### **1. 新增 Object Type (对象类型)**\n\n```json\n{\n  \"id\": \"test_report\",\n  \"name\": \"测试报告\",\n  \"description\": \"记录对电池、电芯等产品的性能与安全测试结果与报告。\",\n  \"icon\": \"Document\", // 使用文档图标，与报告性质相符\n  \"backing_dataset\": \"test_report_dataset\", // 【重要】请替换为您的实际数据集名称\n  \"industryId\": null,\n  \"createdAt\": \"2026-04-11T10:30:00\", // 示例时间，系统会自动生成\n  \"updatedAt\": \"2026-04-11T10:30:00\",\n  \"status\": \"active\",\n  \"properties\": [\n    {\n      \"id\": \"p_report_id_test_report\",\n      \"objectTypeId\": \"test_report\",\n      \"name\": \"测试报告编号\",\n      \"type\": \"string\",\n      \"description\": \"测试报告的唯一编号\",\n      \"isPrimaryKey\": 1, // 作为主键\n      \"baseColumn\": \"report_id\", // 假设数据集中有此列\n      \"typeClasses\": null,\n      \"sortOrder\": 0\n    },\n    {\n      \"id\": \"p_test_item_test_report\",\n      \"objectTypeId\": \"test_report\",\n      \"name\": \"测试项目\",\n      \"type\": \"string\",\n      \"description\": \"例如：过充测试、短路测试、循环寿命测试、能量密度测试\",\n      \"isPrimaryKey\": 0,\n      \"baseColumn\": \"test_item\",\n      \"typeClasses\": null,\n      \"sortOrder\": 1\n    },\n    {\n      \"id\": \"p_test_standard_test_report\",\n      \"objectTypeId\": \"test_report\",\n      \"name\": \"测试标准\",\n      \"type\": \"string\",\n      \"description\": \"依据的国标、行标或企标，如GB/T 31484-2015\",\n      \"isPrimaryKey\": 0,\n      \"baseColumn\": \"test_standard\",\n      \"typeClasses\": null,\n      \"sortOrder\": 2\n    },\n    {\n      \"id\": \"p_test_result_test_report\",\n      \"objectTypeId\": \"test_report\",\n      \"name\": \"测试结果\",\n      \"type\": \"string\",\n      \"description\": \"通过/不通过，或具体的性能数值\",\n      \"isPrimaryKey\": 0,\n      \"baseColumn\": \"test_result\",\n      \"typeClasses\": null,\n      \"sortOrder\": 3\n    },\n    {\n      \"id\": \"p_test_date_test_report\",\n      \"objectTypeId\": \"test_report\",\n      \"name\": \"测试日期\",\n      \"type\": \"date\",\n      \"description\": null,\n      \"isPrimaryKey\": 0,\n      \"baseColumn\": \"test_date\",\n      \"typeClasses\": null,\n      \"sortOrder\": 4\n    },\n    {\n      \"id\": \"p_test_in, ontology=null, streaming=false}]', NULL, 'project_public', '2026-04-11 10:27:43', '2026-04-11 10:28:15');
