INSERT INTO `news_events` (`id`, `title`, `summary`, `content`, `category`, `source`, `event_date`, `tags`, `project_id`, `created_at`, `updated_at`) VALUES ('news_catl_cet_001', '宁德时代与中恒电气达成储能协同合作', '合作消息触发市场对储能产业链关系的重新梳理，研究员希望确认合作关系是否足以沉淀为图谱中的正式关系。', '宁德时代与中恒电气宣布围绕储能场景展开协同合作，合作方向包括储能系统集成、站端设备协同与项目拓展。市场关注这是否意味着双方将在储能领域形成更明确的合作关系。', '关系发现', '证券时报', '2026-04-15', '[\"储能\", \"合作关系\"]', 'project_public', '2026-04-15 22:56:35', '2026-04-16 11:07:13');
INSERT INTO `news_events` (`id`, `title`, `summary`, `content`, `category`, `source`, `event_date`, `tags`, `project_id`, `created_at`, `updated_at`) VALUES ('news_charging_policy_001', '政策支持充电基础设施建设', '政策端继续强调充电基础设施建设和补能网络完善，市场关注其对充电运营、设备制造及整车消费渗透的带动效应。', '政策端继续强调充电基础设施建设和补能网络完善，市场关注其对充电运营、设备制造及整车消费渗透的带动效应。', '政策驱动', '证券时报', '2026-04-14', '[\"充电基础设施\", \"高压快充\", \"新能源汽车\"]', 'project_public', '2026-04-15 22:56:35', '2026-04-16 07:13:59');
