INSERT INTO `news_multisource` (`id`, `texttitle`, `entrytime`, `medianame`, `authors`, `abs`, `originalurl`) VALUES (167, '合资品牌“回归”、自主品牌“冲高” 北京车展上演“诸神之战”|北京车展季', '2026-04-26 21:42:27', '财联社', '财联社记者 刘阳', '①记者了解到，在此次车展中，有来自21个国家和地区的2000多家企业一起参展，现场共展出1451辆车辆。 ②在车展现场，东风汽车、长安汽车、北汽集团、上汽集团、广汽集团等央国企代表旗下品牌展出了大量新品。', NULL);
INSERT INTO `news_multisource` (`id`, `texttitle`, `entrytime`, `medianame`, `authors`, `abs`, `originalurl`) VALUES (168, '苹果新CEO接棒前，果链公司的业绩先分化了', '2026-04-26 18:29:39', '财联社', '财联社记者 王碧微', '①A股果链公司2026年一季度表现分化；\n②多家公司提到，存储涨价、汇率波动、原材料成本上涨影响一季度经营表现；\n③苹果换帅后，市场普遍关注约翰·特努斯在AI、产品工程和折叠屏等新产品形态上的推进节奏。', NULL);
