INSERT INTO `news_multisource` (`id`, `texttitle`, `entrytime`, `medianame`, `authors`, `abs`, `originalurl`) VALUES (170, '一季度“固收+”爆发，规模冲上3万亿，新排名出炉', '2026-04-26 21:43:16', '财联社', '财联社记者 吴雨其', '① 一季度“固收+”基金规模达到3.15万亿元，较去年末增加4663.40亿元，成为公募规模增长的重要增量。\n② 二级债基贡献主要增量，景顺长城旗下多只产品规模增长突出，景颐双利规模突破600亿元。\n③ 大体量“固收+”产品近一年、近三年收益多数保持为正。', NULL);
INSERT INTO `news_multisource` (`id`, `texttitle`, `entrytime`, `medianame`, `authors`, `abs`, `originalurl`) VALUES (171, '“AI老法师”上岗记：当大模型接管工厂，让“制造”像生命一样进化', '2026-04-26 18:29:52', '财联社', '财联社记者 张校毓', '①财联社记者近日走访上海交通大学人工智能与微结构实验室了解“AI老法师”背后的故事；\n②作为上海交大培养的科研领军人物，李金金教授创立上海金珵科技，愿景是让AI赋能中国制造业；\n③目前，金珵科技优先赋能“国之重器”，其大模型已落地几十家上市企业，累计帮助合作企业获得上亿经济效益。', NULL);
