INSERT INTO `news_multisource` (`id`, `texttitle`, `entrytime`, `medianame`, `authors`, `abs`, `originalurl`) VALUES (507, 'G7央行将“围猎”通胀？全球经济“半壁江山”的命运 就在这三天！', '2026-04-27 08:40:25', '财联社', '财联社 潇湘', '①本周，美、欧、日、英、加等主要央行都将相继公布利率决议；\n②这构成了全球金融市场罕见的“超级央行周”——七国集团(G7)成员国央行将集体出动，这些掌握全球约一半经济命脉的决策者们，将各自为未来的货币政策定调。', NULL);
INSERT INTO `news_multisource` (`id`, `texttitle`, `entrytime`, `medianame`, `authors`, `abs`, `originalurl`) VALUES (508, '大摩：与以往技术革命相比，AI扩散更快，但“尚未出现冲垮就业”的迹象', '2026-04-27 11:08:07', '华尔街见闻', NULL, '摩根士丹利首席经济学家最新研究揭示：AI是工业革命以来第六次重大创新浪潮，扩散速度远超历史任何技术革命。当前就业数据异乎寻常地稳定，AI更多扮演\"增量器\"而非\"替代者\"——高暴露行业生产率提升由产出加速驱动，而非裁员。但警告已然拉响：压缩的调整周期意味着冲击或猝不及防，政策应对能力将是决定就业代价深浅的最后防线。', NULL);
