INSERT INTO `news_multisource` (`id`, `texttitle`, `entrytime`, `medianame`, `authors`, `abs`, `originalurl`) VALUES (577, '美股财报季进入关键周：“五巨头”将集中亮相 近1/3标普500成分股公布业绩', '2026-04-27 11:45:18', '财联社', '财联社 刘蕊', '①本周，美股财报季进入关键阶段，五家科技巨头（亚马逊、谷歌母公司Alphabet、微软、Meta和苹果）将集中公布财报；\n②同时，标普500指数成分股中近三分之一的公司也会在本周公布财报。截至上周五，标普500指数公司中已有138家公司公布了第一季度财报。', NULL);
