INSERT INTO `news_multisource` (`id`, `texttitle`, `entrytime`, `medianame`, `authors`, `abs`, `originalurl`) VALUES (781, 'PCB板块爆发背后：伊朗战争冲击供应链 + AI需求引爆涨价潮 + 季报全线高增', '2026-04-27 15:28:06', '华尔街见闻', NULL, '伊朗战争扰乱PPE树脂供应，单月推动PCB价格暴涨40%，高盛预期云服务提供商愿意接受进一步涨价；与此同时，AI服务器需求持续爆发，国内PCB企业一季报净利润普遍翻倍。机构判断高阶AI PCB产能今年将接近倍增，景气有望延续至明年，2026年全球PCB行业规模将增长12.5%。', NULL);
