INSERT INTO `news_multisource` (`id`, `texttitle`, `entrytime`, `medianame`, `authors`, `abs`, `originalurl`) VALUES (900, '韩国散户“扫货全球半导体”：中国PCB牛股进入TOP50龙虎榜', '2026-04-27 16:14:15', '财联社', '财联社 史正丞', '①韩国证券存管机构数据显示，4月韩国散户大举加仓全球半导体资产，NAND概念股铠侠与PCB巨头胜宏科技罕见跻身海外净买入TOP50榜单；\n②与此同时，韩国投资者仍通过三倍做多半导体ET押注AI算力与存储景气周期，并同步增配华虹半导体、宁德时代等中资科技资产。', NULL);
INSERT INTO `news_multisource` (`id`, `texttitle`, `entrytime`, `medianame`, `authors`, `abs`, `originalurl`) VALUES (901, '美国已打空半数导弹储备？研究称重建库存或需长达四年', '2026-04-27 15:21:30', '财联社', '财联社 马兰', '①美伊冲突使美国武器库存大幅消耗，精确打击导弹、THAAD拦截器和爱国者拦截导弹等主要弹药储备大幅减少；\n②美国国防部计划投资5亿美元提高武器产量，并将2027财年国防预算上调至1.5万亿美元；\n③专家指出美国在伊朗冲突中缺乏廉价拦截武器，需考虑如何补充弹药。', NULL);
