INSERT INTO `news_multisource` (`id`, `texttitle`, `entrytime`, `medianame`, `authors`, `abs`, `originalurl`) VALUES (975, '台积电加速扩产：3nm预计增20%至18万片/月，2nm年底达10万片', '2026-04-27 16:00:19', '华尔街见闻', NULL, '台积电股价周一上涨3%至历史新高，背后是硬核扩产逾期支撑：3nm月产能目标上调至18万片，较原计划增加20%；2nm产线订单全满，年底冲刺10万片/月。CEO魏哲家直言，供应缺口将延续至2027年，AI算力军备竞赛正将台积电推向前所未有的战略高位。', NULL);
