INSERT INTO `news_multisource` (`id`, `texttitle`, `entrytime`, `medianame`, `authors`, `abs`, `originalurl`) VALUES (977, '史上两大IPO项目对簿公堂：马斯克诉OpenAI案今日开庭，或影响双方上市进程', '2026-04-27 16:00:19', '华尔街见闻', NULL, '若马斯克胜诉，OpenAI或被迫撤销营利架构并重组领导层，导致其8520亿美元的IPO计划化为泡影，甚至波及全球AI产业供应链；若OpenAI获胜，将扫清上市最大法律障碍，与SpaceX竞逐史上最大规模IPO桂冠。此案裁决将直接决定未来AI治理模式及万亿级资本市场的走向。', NULL);
